class Solution {
public:
int findKthElement(int n, int* nums, int k) {
	int num_heap = 0;
	int next_heap = 1;
	int next_heap_pos = 1;
	while (num_heap < n) {
		// Push an element into the heap
		int heap_next_pos = next_heap_pos;
		int next_heap_pos_new = (next_heap_pos + 1) / 2;
		while (num_heap * 2 + 2 <= next_heap_pos_new) {
			// Bubble up the element to maintain heap order
			heapify_up(nums, num_heap);
			++num_heap;
			// Update the new heap position
			next_heap_pos_new = (next_heap_pos_new + 1) / 2;
		}
		// Update the new heap position
		next_heap_pos = next_heap_pos_new;
		// Pop the maximum element
		if (next_heap_pos <= k) {
			int next_heap_pos_new = 2 * next_heap_pos;
			// Swap the last element with the next element to maintain heap order
		tswap(nums, next_heap_pos - 1, next_heap_pos_new - 1);
			// Pop the maximum element
		return nums[next_heap_pos_new - 1];
		}
		// Bubble up the maximum element to maintain heap order
		next_heap_pos = next_heap_pos_new;
	}
	// Return the kth element
	return nums[num_heap];
}

template<typename T>
void heapify_up(T* nums, int index) {
	while (index > 0) {
		T h = nums[index];
		int parent_idx = (index - 1) / 2;
		if (nums[parent_idx] > h) {
			nums[index] = nums[parent_idx];
			index = parent_idx;
		} else {
			nums[index] = h;
			index = parent_idx;
		}
	}
	return;
}
